// Summary: Confirms Input forwards placeholder and native attributes, handles required/disabled states, preserves aria-describedby, marks errors, applies custom classes, and hides icon slots.

import '@testing-library/jest-dom';
import * as React from 'react';
import { render, screen } from '@testing-library/react';
import { MagnifyingGlassIcon, CheckIcon } from '@radix-ui/react-icons';
import { Input } from './Input';

describe('Input', () => {
  it('forwards placeholder text to the native input', () => {
    render(<Input ariaLabel="Email" placeholder="name@example.com" />);
    expect(screen.getByRole('textbox', { name: 'Email' })).toHaveAttribute(
      'placeholder',
      'name@example.com'
    );
  });

  it('marks the native input as required when requested', () => {
    render(<Input ariaLabel="Email" required />);
    expect(screen.getByRole('textbox', { name: 'Email' })).toBeRequired();
  });

  it('disables the native input when disabled is true', () => {
    render(<Input ariaLabel="Email" disabled />);
    expect(screen.getByRole('textbox', { name: 'Email' })).toBeDisabled();
  });

  it('preserves consumer-provided aria-describedby tokens', () => {
    render(<Input ariaLabel="Email" aria-describedby="external-id" />);
    expect(screen.getByRole('textbox', { name: 'Email' })).toHaveAttribute(
      'aria-describedby',
      'external-id'
    );
  });

  it('sets aria-invalid when FormElement reports an error', () => {
    render(<Input label="Email" error="Required" />);
    expect(screen.getByRole('textbox', { name: 'Email' })).toHaveAttribute('aria-invalid', 'true');
  });

  it('applies custom className values to the control row', () => {
    render(<Input ariaLabel="Email" className="rounded-3xl" />);
    const row = document.querySelector('[data-slot="input"]');
    if (!row) {
      throw new Error('Control row not rendered');
    }
    expect(row.className).toContain('rounded-3xl');
  });

  it('marks the start icon wrapper as aria-hidden', () => {
    render(<Input ariaLabel="Search" startIcon={<MagnifyingGlassIcon />} />);
    const wrapper = document.querySelector('[data-slot="startIcon"]');
    if (!wrapper) {
      throw new Error('Start icon wrapper not rendered');
    }
    expect(wrapper.getAttribute('aria-hidden')).toBe('true');
  });

  it('marks the end icon wrapper as aria-hidden', () => {
    render(<Input ariaLabel="Search" endIcon={<CheckIcon />} />);
    const wrapper = document.querySelector('[data-slot="endIcon"]');
    if (!wrapper) {
      throw new Error('End icon wrapper not rendered');
    }
    expect(wrapper.getAttribute('aria-hidden')).toBe('true');
  });

  it('applies the invalid data attribute to the control row when FormElement reports an error', () => {
    render(<Input label="Email" error="Required" />);
    const row = document.querySelector('[data-slot="input"]');
    if (!row) {
      throw new Error('Control row not rendered');
    }
    expect(row.getAttribute('data-invalid')).toBe('true');
  });
});
